# ASTU Analytics - Apply All Fixes
$base = $PSScriptRoot
Write-Host "" 
Write-Host "Applying fixes..." -ForegroundColor Cyan

New-Item -ItemType Directory -Force -Path "$base\college-service\src\controllers" | Out-Null
[System.IO.File]::WriteAllBytes("$base\college-service\src\controllers\collegeController.js", [System.Convert]::FromBase64String(""))
Write-Host "  fixed: college-service\src\controllers\collegeController.js" -ForegroundColor Green
New-Item -ItemType Directory -Force -Path "$base\research-service\src\controllers" | Out-Null
[System.IO.File]::WriteAllBytes("$base\research-service\src\controllers\researchController.js", [System.Convert]::FromBase64String(""))
Write-Host "  fixed: research-service\src\controllers\researchController.js" -ForegroundColor Green
New-Item -ItemType Directory -Force -Path "$base\frontend\src\pages" | Out-Null
[System.IO.File]::WriteAllBytes("$base\frontend\src\pages\ResearchProjects.js", [System.Convert]::FromBase64String(""))
Write-Host "  fixed: frontend\src\pages\ResearchProjects.js" -ForegroundColor Green
New-Item -ItemType Directory -Force -Path "$base\frontend\src\pages" | Out-Null
[System.IO.File]::WriteAllBytes("$base\frontend\src\pages\Dashboard.js", [System.Convert]::FromBase64String(""))
Write-Host "  fixed: frontend\src\pages\Dashboard.js" -ForegroundColor Green
New-Item -ItemType Directory -Force -Path "$base\frontend\src\pages" | Out-Null
[System.IO.File]::WriteAllBytes("$base\frontend\src\pages\Reports.js", [System.Convert]::FromBase64String(""))
Write-Host "  fixed: frontend\src\pages\Reports.js" -ForegroundColor Green
New-Item -ItemType Directory -Force -Path "$base\frontend\src\pages" | Out-Null
[System.IO.File]::WriteAllBytes("$base\frontend\src\pages\Settings.js", [System.Convert]::FromBase64String(""))
Write-Host "  fixed: frontend\src\pages\Settings.js" -ForegroundColor Green

Write-Host ""
Write-Host "All fixes applied!" -ForegroundColor Green
Write-Host ""
Write-Host "IMPORTANT: Restart all services for changes to take effect:" -ForegroundColor Yellow
Write-Host "  Stop each terminal (Ctrl+C) and run npm start again" -ForegroundColor Yellow
Write-Host "  Then go to Settings and click Initialise Database" -ForegroundColor Yellow
Write-Host ""
